INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a07c1900-0000-4000-8000-000000000000','a07c0000-0000-4000-8000-000000000000','確認テスト ─ 小さな場を仕切る','quiz',NULL,NULL,NULL,3,2),
  ('a07c2900-0000-4000-8000-000000000000','a07c0000-0000-4000-8000-000000000000','確認テスト ─ 主任の打診が来たら','quiz',NULL,NULL,NULL,3,4)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a07c1900-0000-4000-8000-000000000000','本文で言う「司会」と「仕切る人」の違いはどれか。','司会は順番に項目を読み上げる係、仕切る人は場が目的に向かっているかを見てずれたら戻す人','司会は権限を持つ人、仕切る人は権限を持たない人','司会は決裁する人、仕切る人は議論を裁いて結論を出す人','司会は場の全体を見る人、仕切る人は自分の番だけを話す人','A',0),
('a07c1900-0000-4000-8000-000000000000','本文が定義する「仕切る」の本質はどれか。','司会をして議論を裁き、結論を出すこと','場が目的と時間から外れたとき、それを戻す一言を出すこと','自分の意見を場の結論へ誘導すること','出た意見をすべて丁寧に拾い切ること','B',1),
('a07c1900-0000-4000-8000-000000000000','「仕切ろうとして、司会を奪う」失敗への修正として本文が挙げるのはどれか。','自分が進行を引き取り、決めちゃいませんかと言い切る','気づいた一言を飲み込み、黙って場を見守る','形を必ず「問い」か「確認」にし、主語を司会に残す','自分の結論を先に示し、その方向へ誘導する','C',2),
('a07c2900-0000-4000-8000-000000000000','本文が言う、できる人ほど主任で潰れる理由はどれか。','本人の能力が不足しているから','部下の能力が低く、成果が出ないから','やり方を切り替えそびれ、優秀さがそのまま足かせになるから','上司が十分な権限を与えないから','C',0),
('a07c2900-0000-4000-8000-000000000000','本文が一行で言う、プレイヤーと管理者の違いはどれか。','プレイヤーは自分で成果を出す、管理者は人に成果を出させる','プレイヤーは待つ人、管理者は動く人','プレイヤーは評価する人、管理者は評価される人','プレイヤーは道を作る人、管理者は道を走る人','A',1),
('a07c2900-0000-4000-8000-000000000000','打診を受けた夜の不安を分解した三つのうち、本文が「一番重い」とするのはどれか。','技術への不安','人への不安','時間への不安','自分への不安(器の問題)','D',2);
